mapper.select:
SELECT U.USER_ID AS "userId", U.USER_NAME AS "userName", U.BRANCH_ID AS "branchId", U.AUTH_GROUP_ID AS "authGroupId", G.AUTH_GROUP_NAME AS "authGroupName", U.USE_YN AS "useYn", U.LAST_LOGIN_TIME AS "lastLoginTime" FROM OM_USER U LEFT JOIN OM_AUTH_GROUP G ON U.AUTH_GROUP_ID = G.AUTH_GROUP_ID WHERE 1 = 1
AND U.USER_ID LIKE '%' || #{userId} || '%'
AND U.USER_NAME LIKE '%' || #{userName} || '%'
AND U.BRANCH_ID = #{branchId}
AND U.AUTH_GROUP_ID = #{authGroupId}
AND U.USE_YN = #{useYn}
ORDER BY U.USER_ID
OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
  FROM OM_USER U
 WHERE 1 = 1

    AND U.USER_ID LIKE '%' || #{userId} || '%'


    AND U.USER_NAME LIKE '%' || #{userName} || '%'


    AND U.BRANCH_ID = #{branchId}


    AND U.AUTH_GROUP_ID = #{authGroupId}


    AND U.USE_YN = #{useYn}

mapper.update:
UPDATE OM_USER
   SET USER_NAME = #{userName},
       BRANCH_ID = #{branchId},
       AUTH_GROUP_ID = #{authGroupId},
       USE_YN = #{useYn}
 WHERE USER_ID = #{userId}

UPDATE OM_USER
   SET LAST_LOGIN_TIME = #{lastLoginTime}
 WHERE USER_ID = #{userId}

UPDATE OM_USER
   SET PASSWORD_HASH = #{passwordHash}
 WHERE USER_ID = #{userId}

