SELECT M.MENU_ID AS "menuId", M.MENU_NAME AS "menuName", COALESCE(M.MENU_URL, '') AS "menuUrl", COALESCE(M.PARENT_MENU_ID, '') AS "parentMenuId", COALESCE(P.MENU_NAME, '') AS "parentMenuName", M.SORT_ORDER AS "sortOrder", M.USE_YN AS "useYn" FROM OM_MENU M LEFT JOIN OM_MENU P ON P.MENU_ID = M.PARENT_MENU_ID WHERE 1 = 1
AND M.MENU_ID = #{menuId}
AND M.MENU_NAME LIKE '%' || #{menuName} || '%'
AND M.USE_YN = #{useYn}
ORDER BY M.SORT_ORDER, M.MENU_ID

SELECT COUNT(*) FROM OM_MENU
 WHERE PARENT_MENU_ID = #{menuId}
   AND USE_YN = 'Y'

