AND AUTH_GROUP_ID = #{authGroupId}
AND AUTH_GROUP_NAME LIKE '%' || #{authGroupName} || '%'
AND USE_YN = #{useYn}
ORDER BY AUTH_GROUP_ID

mapper.update:
